$ErrorActionPreference="Stop";$root=Split-Path -Parent $PSScriptRoot;$godot=Get-ChildItem -LiteralPath (Join-Path $root ".tools\Godot") -Recurse -Filter "Godot*_mono_win64_console.exe"|Select-Object -First 1
foreach($room in 27..28){$ErrorActionPreference="Continue";$o=& $godot.FullName --headless --fixed-fps 60 --path $root "res://scenes/Room$room.tscn" --quit-after 30000 -- "--room$room-solution-smoke" 2>&1;$e=$LASTEXITCODE;$ErrorActionPreference="Stop";$o|Write-Output;if($e -ne 0){throw "Room $room solution smoke failed with $e"};if(($o-join"`n")-notmatch"ROOM${room}_SOLUTION_PASS"){throw "Room $room did not complete ten runs."}}
